        "title": "[Swagger] Springboot + swagger",
        "excerpt":"   maven dependency 추가      &lt;dependency&gt;    &lt;groupId&gt;io.springfox&lt;/groupId&gt;    &lt;artifactId&gt;springfox-swagger2&lt;/artifactId&gt;    &lt;version&gt;2.9.2&lt;/version&gt;  &lt;/dependency&gt;  &lt;dependency&gt;    &lt;groupId&gt;io.springfox&lt;/groupId&gt;    &lt;artifactId&gt;springfox-swagger-ui&lt;/artifactId&gt;    &lt;version&gt;2.9.2&lt;/version&gt;  &lt;/dependency&gt;                javacofnig 생성              /src/main/java/com/example/swagger/config/SwaggerConfig.java            package com.example.swagger.config;   import org.springframework.context.annotation.Bean;  import org.springframework.context.annotation.Configuration;  import springfox.documentation.builders.PathSelectors;  import springfox.documentation.builders.RequestHandlerSelectors;  import springfox.documentation.spi.DocumentationType;  import springfox.documentation.spring.web.plugins.Docket;  import springfox.documentation.swagger2.annotations.EnableSwagger2;   @Configuration  @EnableSwagger2   public class SwaggerConfig {       @Bean       public Docket api() {          return new Docket(DocumentationType.SWAGGER_2)              .select()              .apis(RequestHandlerSelectors.any())              // .apis(RequestHandlerSelectors.basePackage(\"java.com.example.swagger.controller\"))              .paths(PathSelectors.any())              .build();      }  }                test controller 생성              /src/main/java/com/example/swagger/controller/BoardController.java           package com.example.swagger.controller;  import io.swagger.annotations.ApiImplicitParam; import io.swagger.annotations.ApiImplicitParams; import io.swagger.annotations.ApiOperation; import org.springframework.beans.factory.annotation.Autowired; import org.springframework.web.bind.annotation.*;  import java.util.Map; import java.util.HashMap; import java.util.List;  @RestController @RequestMapping(\"/api\") public class BoardController {      @ApiOperation(value = \"전체 게시판 조회\")     @RequestMapping(value = \"/board\", method = RequestMethod.GET)     public Map &lt; String, Object &gt; selectListBoard() {         Map&lt;String, Object&gt; result = new HashMap&lt;String, Object&gt;();         result.put(\"key\", \"value 1234\");         return result;     }      @ApiOperation(value = \"해당 게시판 조회\")     @ApiImplicitParams({         @ApiImplicitParam(name = \"id\", value = \"게시판 고유키\", required = true, dataType = \"string\", paramType = \"path\", defaultValue = \"\"),     })     @RequestMapping(value = \"/board/{id}\", method = RequestMethod.GET)     public Map &lt; String, Object &gt; selectOneBoard(@PathVariable(\"id\") Integer id) {         Map&lt;String, Object&gt; result = new HashMap&lt;String, Object&gt;();         result.put(\"id\", id);         return result;     }  }                확인 http://localhost:8080/swagger-ui.html       annotation 설명            @Api : 컨트롤러에 설명을 추가       @ApiOperation : API에 설명을 추가       @ApiParam : API의 파라미터에 설명을 추가       @ApiModel : 모델에 설명을 추가       @ApiModelProperty : 모델의 요소에 설명을 추가          ","categories": ["Framework"],
        "tags": ["swagger","Springboot"],
        "url": "http://localhost:4000/framework/framework-springboot-swagger/",
